#define     NET_SIZE      12240064
#define     INPUTDATA_SIZE 5537792

// -------- Post process --------
#if (NET_TYPE == NetType_Object_Detect)
    #define     YOLO3_DETECTION_OUTPUT       1       // only for yolo3
#endif

// -------- debug information print ----------
//#define EEP_DEBUG_INFO

// -------- Camera Settings -----------
