#define IMG_RGB565 // set input image type: rgb or gray
#define IMG_HEIGHT 720
#define IMG_WIDTH  1280

// ------- SD card Enable -------------
#define SD_CARD_IS_READY

// ------- SD card Enable -------------
#define EEP_DP_ENABLE


