115		if (net_in_c == 3)
116		{
117			resize_bilinear_c3(inputbuf, img_w, img_h, inbuf_resized, net_in_w, net_in_h);
118		}
119		else if (net_in_c == 1)
120		{
121			resize_bilinear_c1(inputbuf, img_w, img_h, inbuf_resized, net_in_w, net_in_h);
122		}
123	
124		// set to hw format
125		// inputbuf:  hwc
126		*inlen = net_in_w*net_in_h*32;
127		memset(inbuf, 0, *inlen);
