647					    for (int i = 0; i < blob_out.h; i++)
648					    {
649					        const float *values = blob_out.row(i);
650	
651					        int label = values[0];
652					        float prob = values[1];
653					        float scale_x = values[2];
654					        float scale_y = values[3];
655					        float scale_w = values[4];
656					        float scale_h = values[5];
657	
658					        if(scale_x < 0) scale_x = 0;
659					        if(scale_y < 0) scale_y = 0;
660					        if(scale_w < 0) scale_w = 0;
661					        if(scale_h < 0) scale_h = 0;
662	
663						    x = scale_x * pic_hsize;
664						    y = scale_y * pic_vsize;
665						    w = scale_w * pic_hsize;
666						    h = scale_h * pic_vsize;
667	
668					        xil_printf("Obj[%d]: %2d(%10s)  %f; At (%f,%f)  %f x %f\n", i, label, class_names[label], prob, scale_x, scale_y, scale_w, scale_h);
669					    }
670		            #endif
671					    top_blobs.clear();
672					#endif
673	
674					    outputs.clear();
675	
676					    eepsa.eeptpu_deinit();
677	
678					#ifdef EEP_DP_ENABLE
679					    // dp display
680					    dp_display(pic_hsize, pic_vsize, img_data_888, ARGB);
681			    	#endif
682					}
683					break;
684				default:
685					break;
686			}
687	    #ifdef EEP_DEBUG_INFO
688			if(exit_flag != 1) {
689				print("Press any key to return to main menu\r\n");
690				inbyte();
691			}
692	    #endif
693		}
694	
695	    cleanup_platform();
696	
697	    return 0;
698	}
